arguments.file_text:
@page "/patients"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patient Records</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search pets or owners..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowAddOwner">
            <span class="bi bi-plus"></span> New Owner
        </button>
        <button class="btn btn-success ms-2" @onclick="ShowAddPet">
            <span class="bi bi-plus"></span> New Pet
        </button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner?.Id > 0 ? "Edit" : "New") Owner</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.FirstName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.LastName" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.Phone" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner!.Email" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Address</label>
                    <InputText class="form-control" @bind-Value="editingOwner!.Address" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="CancelOwnerForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet?.Id > 0 ? "Edit" : "New") Pet</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet!.Name" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="editingPet!.Species">
                            <option value="">Select...</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet!.Breed" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet!.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-3 mb-2">
