@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = new();
    private List<Pet> pets = new();
    private List<DateTime> availableSlots = new();
    private bool showForm;
    private Appointment? editingAppointment;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadPets();
        await LoadAppointments();
    }

    private async Task LoadPets()
    {
        using var db = DbFactory.CreateDbContext();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task LoadAppointments()
    {
        using var db = DbFactory.CreateDbContext();
        var dayStart = selectedDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var clinicStart = selectedDate.Date.AddHours(8);
        var clinicEnd = selectedDate.Date.AddHours(18);

        for (var slot = clinicStart; slot < clinicEnd; slot = slot.AddMinutes(30))
        {
            var slotEnd = slot.AddMinutes(30);
            var isOccupied = appointments
                .Where(a => a.Status != AppointmentStatus.Cancelled)
                .Any(a => a.StartTime < slotEnd && a.EndTime > slot);
            if (!isOccupied)
            {
                availableSlots.Add(slot);
            }
        }
    }

    private void ShowNewAppointment()
    {
        var nextSlot = availableSlots.FirstOrDefault();
        if (nextSlot == default) nextSlot = selectedDate.Date.AddHours(9);
        editingAppointment = new Appointment
        {
            StartTime = nextSlot,
            EndTime = nextSlot.AddMinutes(30)
        };
        showForm = true;
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = new Appointment
        {
            Id = appt.Id,
            PetId = appt.PetId,
            StartTime = appt.StartTime,
            EndTime = appt.EndTime,
            Reason = appt.Reason,
            Veterinarian = appt.Veterinarian,
            Status = appt.Status,
            Notes = appt.Notes
        };
        showForm = true;
    }

    private async Task Cancel(Appointment appt)
    {
        using var db = DbFactory.CreateDbContext();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
            statusMessage = "Appointment cancelled.";
            await LoadAppointments();
        }
    }

    private async Task SaveAppointment()
    {
        using var db = DbFactory.CreateDbContext();
        if (editingAppointment!.Id == 0)
        {
            db.Appointments.Add(editingAppointment);
        }
        else
        {
            db.Appointments.Update(editingAppointment);
        }
        await db.SaveChangesAsync();
        statusMessage = "Appointment saved.";
        showForm = false;
        selectedDate = editingAppointment.StartTime.Date;
        await LoadAppointments();
    }

    private void PreviousDay() { selectedDate = selectedDate.AddDays(-1); _ = LoadAppointments(); }
    private void NextDay() { selectedDate = selectedDate.AddDays(1); _ = LoadAppointments(); }
    private void Today() { selectedDate = DateTime.Today; _ = LoadAppointments(); }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        AppointmentStatus.InProgress => "table-info",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Confirmed => "bg-info",
        AppointmentStatus.InProgress => "bg-warning text-dark",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-secondary",
        _ => "bg-primary"
    };
}

