    private string searchTerm = string.Empty;
    private string? statusMessage;

    private bool showOwnerForm;
    private bool showPetForm;
    private Owner? editingOwner;
    private Pet? editingPet;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = DbFactory.CreateDbContext();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
        filteredPets = pets;
    }

    private void Search()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPets = pets;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPets = pets.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Species.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FullName.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void ShowAddOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowAddPet()
    {
        editingPet = new Pet { DateOfBirth = DateTime.Today.AddYears(-1) };
        showPetForm = true;
        showOwnerForm = false;
    }

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id,
            Name = pet.Name,
            Species = pet.Species,
            Breed = pet.Breed,
            DateOfBirth = pet.DateOfBirth,
            Weight = pet.Weight,
            Color = pet.Color,
            MicrochipNumber = pet.MicrochipNumber,
            OwnerId = pet.OwnerId
        };
        showPetForm = true;
        showOwnerForm = false;
    }

    private async Task SaveOwner()
    {
        using var db = DbFactory.CreateDbContext();
        if (editingOwner!.Id == 0)
        {
            db.Owners.Add(editingOwner);
        }
        else
        {
            db.Owners.Update(editingOwner);
        }
        await db.SaveChangesAsync();
        statusMessage = $"Owner '{editingOwner.FullName}' saved successfully.";
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        using var db = DbFactory.CreateDbContext();
        if (editingPet!.Id == 0)
        {
            db.Pets.Add(editingPet);
        }
        else
        {
            db.Pets.Update(editingPet);
        }
        await db.SaveChangesAsync();
        statusMessage = $"Pet '{editingPet.Name}' saved successfully.";
        showPetForm = false;
        await LoadData();
    }

    private void CancelOwnerForm() => showOwnerForm = false;
    private void CancelPetForm() => showPetForm = false;

    private string GetAge(DateTime dob)
    {
        var age = DateTime.Today.Year - dob.Year;
        if (dob.Date > DateTime.Today.AddYears(-age)) age--;
        return age <= 0 ? "< 1 year" : $"{age} years";
    }
}

