            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>$@item.UnitPrice.ToString("F2")</td>
                    <td>$@item.Total.ToString("F2")</td>
                </tr>
            }
        </tbody>
    </table>

    <h4>Payment History</h4>
    <button class="btn btn-success mb-3" @onclick="ShowPaymentForm">+ Record Payment</button>

    @if (showPayForm)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment</div>
            <div class="card-body">
                <EditForm Model="newPayment" OnValidSubmit="SavePayment" FormName="payForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="newPayment!.Amount" />
                        </div>
                        <div class="col-md-3 mb-2">
