                            <InputText class="form-control" @bind-Value="newPayment!.Reference" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Status</label>
                            <InputSelect class="form-select" @bind-Value="newPayment!.Status">
                                @foreach (var s in Enum.GetValues<PaymentStatus>())
                                {
                                    <option value="@s">@s</option>
                                }
                            </InputSelect>
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newPayment!.Notes" />
                    </div>
                    <button type="submit" class="btn btn-success">Save Payment</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPayForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (statusMessage != null)
    {
        <div class="alert alert-success alert-dismissible">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    @if (invoice.Payments.Any())
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Amount</th>
                    <th>Method</th>
                    <th>Reference</th>
                    <th>Status</th>
                    <th>Notes</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pay in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                {
                    <tr>
                        <td>@pay.PaymentDate.ToShortDateString()</td>
                        <td>$@pay.Amount.ToString("F2")</td>
                        <td>@pay.Method</td>
                        <td>@pay.Reference</td>
                        <td><span class="badge @GetPayBadge(pay.Status)">@pay.Status</span></td>
                        <td>@pay.Notes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }
}

@code {
    [Parameter] public int InvoiceId { get; set; }

    private Invoice? invoice;
    private bool showPayForm;
    private Payment? newPayment;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        using var db = DbFactory.CreateDbContext();
        invoice = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == InvoiceId);
    }

    private void ShowPaymentForm()
    {
        newPayment = new Payment
        {
            InvoiceId = InvoiceId,
            Amount = invoice!.BalanceDue,
            Method = PaymentMethod.Cash,
            Status = PaymentStatus.Completed
        };
        showPayForm = true;
    }

    private async Task SavePayment()
    {
        using var db = DbFactory.CreateDbContext();
        db.Payments.Add(newPayment!);
        await db.SaveChangesAsync();

        // Update invoice status if fully paid
        var inv = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == InvoiceId);
        var totalPaid = inv.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        if (totalPaid >= inv.TotalAmount)
        {
            inv.Status = InvoiceStatus.Paid;
            await db.SaveChangesAsync();
        }

        statusMessage = "Payment recorded.";
        showPayForm = false;
        await LoadInvoice();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };

    private string GetPayBadge(PaymentStatus status) => status switch
    {
        PaymentStatus.Completed => "bg-success",
        PaymentStatus.Pending => "bg-warning text-dark",
        PaymentStatus.Failed => "bg-danger",
        PaymentStatus.Refunded => "bg-info",
        _ => "bg-secondary"
    };
}

