@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing & Invoices</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search invoices..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="FilterInvoices" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingInvoice?.Id > 0 ? "Edit" : "New") Invoice</div>
        <div class="card-body">
            <EditForm Model="editingInvoice" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingInvoice!.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FullName</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Pet (optional)</label>
                        <select class="form-select" @bind="selectedPetId">
                            <option value="">None</option>
                            @foreach (var pet in pets.Where(p => editingInvoice!.OwnerId == 0 || p.OwnerId == editingInvoice.OwnerId))
                            {
                                <option value="@pet.Id">@pet.Name</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Due Date</label>
                        <InputDate class="form-control" @bind-Value="editingInvoice!.DueDate" />
                    </div>
                    <div class="col-md-3 mb-2">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editingInvoice!.Status">
                            @foreach (var s in Enum.GetValues<InvoiceStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <InputText class="form-control" @bind-Value="editingInvoice!.Description" />
                </div>

                <h6>Line Items</h6>
                @for (int i = 0; i < lineItems.Count; i++)
                {
                    var idx = i;
                    <div class="row mb-1">
                        <div class="col-md-5">
                            <input class="form-control form-control-sm" placeholder="Description"
                                   @bind="lineItems[idx].Description" />
                        </div>
