@page "/patients/{PetId:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Navigation

<PageTitle>Patient Details - VetClinic</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>@pet.Name <small class="text-muted">(@pet.Species - @pet.Breed)</small></h1>
        <a href="/patients" class="btn btn-outline-secondary">← Back to List</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Pet Information</div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Owner</dt>
                        <dd class="col-sm-8">@pet.Owner.FullName (@pet.Owner.Phone)</dd>
                        <dt class="col-sm-4">Date of Birth</dt>
                        <dd class="col-sm-8">@pet.DateOfBirth.ToShortDateString()</dd>
                        <dt class="col-sm-4">Weight</dt>
                        <dd class="col-sm-8">@pet.Weight kg</dd>
                        <dt class="col-sm-4">Color</dt>
                        <dd class="col-sm-8">@pet.Color</dd>
                        <dt class="col-sm-4">Microchip</dt>
                        <dd class="col-sm-8">@(string.IsNullOrEmpty(pet.MicrochipNumber) ? "N/A" : pet.MicrochipNumber)</dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <h3>Medical History</h3>

    <button class="btn btn-primary mb-3" @onclick="ShowAddNote">+ Add Treatment Note</button>

    @if (showNoteForm)
    {
        <div class="card mb-3">
            <div class="card-header">@(editingNote?.Id > 0 ? "Edit" : "New") Treatment Note</div>
            <div class="card-body">
                <EditForm Model="editingNote" OnValidSubmit="SaveNote" FormName="noteForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Date</label>
                            <InputDate class="form-control" @bind-Value="editingNote!.Date" />
                        </div>
                        <div class="col-md-4 mb-2">
                            <label class="form-label">Veterinarian</label>
                            <InputText class="form-control" @bind-Value="editingNote!.Veterinarian" />
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Diagnosis</label>
                        <InputText class="form-control" @bind-Value="editingNote!.Diagnosis" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Treatment</label>
                        <InputTextArea class="form-control" rows="2" @bind-Value="editingNote!.Treatment" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Medications</label>
                        <InputText class="form-control" @bind-Value="editingNote!.Medications" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Additional Notes</label>
                        <InputTextArea class="form-control" rows="2" @bind-Value="editingNote!.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary">Save</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showNoteForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (statusMessage != null)
    {
        <div class="alert alert-success alert-dismissible">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    @if (pet.TreatmentNotes.Any())
    {
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Date</th>
                        <th>Veterinarian</th>
                        <th>Diagnosis</th>
                        <th>Treatment</th>
                        <th>Medications</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var note in pet.TreatmentNotes.OrderByDescending(n => n.Date))
                    {
                        <tr>
                            <td>@note.Date.ToShortDateString()</td>
                            <td>@note.Veterinarian</td>
                            <td>@note.Diagnosis</td>
                            <td>@note.Treatment</td>
                            <td>@note.Medications</td>
                            <td>
                                <button class="btn btn-sm btn-warning" @onclick="() => EditNote(note)">Edit</button>
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
    else
    {
        <p class="text-muted">No treatment records yet.</p>
    }
}

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private bool showNoteForm;
    private TreatmentNote? editingNote;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadPet();
    }

    private async Task LoadPet()
    {
        using var db = DbFactory.CreateDbContext();
        pet = await db.Pets
            .Include(p => p.Owner)
            .Include(p => p.TreatmentNotes)
            .FirstOrDefaultAsync(p => p.Id == PetId);
    }

    private void ShowAddNote()
    {
        editingNote = new TreatmentNote
        {
            PetId = PetId,
            Date = DateTime.Today
        };
        showNoteForm = true;
    }

    private void EditNote(TreatmentNote note)
    {
        editingNote = new TreatmentNote
        {
            Id = note.Id,
            PetId = note.PetId,
            Date = note.Date,
            Diagnosis = note.Diagnosis,
            Treatment = note.Treatment,
            Medications = note.Medications,
            Notes = note.Notes,
            Veterinarian = note.Veterinarian
        };
        showNoteForm = true;
    }

    private async Task SaveNote()
    {
        using var db = DbFactory.CreateDbContext();
        if (editingNote!.Id == 0)
        {
            db.TreatmentNotes.Add(editingNote);
        }
        else
        {
            db.TreatmentNotes.Update(editingNote);
        }
        await db.SaveChangesAsync();
        statusMessage = "Treatment note saved.";
        showNoteForm = false;
        await LoadPet();
    }
}

@page "/appointments"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-outline-secondary me-2" @onclick="PreviousDay">← Prev</button>
        <button class="btn btn-outline-secondary me-2" @onclick="Today">Today</button>
        <button class="btn btn-outline-secondary" @onclick="NextDay">Next →</button>
    </div>
    <div class="col-md-4 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment?.Id > 0 ? "Reschedule" : "New") Appointment</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="apptForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment!.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment!.Veterinarian" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment!.Reason" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Start Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment!.StartTime" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">End Time</label>
                        <InputDate Type="InputDateType.DateTimeLocal" class="form-control" @bind-Value="editingAppointment!.EndTime" />
                    </div>
                    <div class="col-md-4 mb-2">
                        <label class="form-label">Status</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment!.Status">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" rows="2" @bind-Value="editingAppointment!.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save</button>
                <button type="button" class="btn btn-secondary ms-2" @onclick="() => showForm = false">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (statusMessage != null)
{
    <div class="alert alert-success alert-dismissible">
        @statusMessage
        <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
    </div>
}

<h4>Schedule for @selectedDate.ToString("dddd, MMMM d, yyyy")</h4>

<div class="row mb-3">
    <div class="col-md-12">
        <h6>Available Slots</h6>
        <div class="d-flex flex-wrap gap-1 mb-3">
            @foreach (var slot in availableSlots)
            {
                <span class="badge bg-success">@slot.ToString("HH:mm")</span>
            }
            @if (!availableSlots.Any())
            {
                <span class="text-muted">No available slots</span>
            }
        </div>
    </div>
</div>

<div class="table-responsive">
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Time</th>
                <th>Pet</th>
                <th>Owner</th>
                <th>Veterinarian</th>
                <th>Reason</th>
                <th>Status</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var appt in appointments)
            {
                <tr class="@GetStatusClass(appt.Status)">
                    <td>@appt.StartTime.ToString("HH:mm") - @appt.EndTime.ToString("HH:mm")</td>
                    <td>@appt.Pet.Name</td>
                    <td>@appt.Pet.Owner.FullName</td>
                    <td>@appt.Veterinarian</td>
                    <td>@appt.Reason</td>
                    <td><span class="badge @GetBadgeClass(appt.Status)">@appt.Status</span></td>
                    <td>
                        <button class="btn btn-sm btn-warning" @onclick="() => Reschedule(appt)">Reschedule</button>
                        @if (appt.Status != AppointmentStatus.Cancelled)
                        {
                            <button class="btn btn-sm btn-danger ms-1" @onclick="() => Cancel(appt)">Cancel</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@if (!appointments.Any())
{
    <p class="text-muted text-center">No appointments scheduled for this day.</p>
}

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> appointments = new();
    private List<Pet> pets = new();
    private List<DateTime> availableSlots = new();
    private bool showForm;
    private Appointment? editingAppointment;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadPets();
        await LoadAppointments();
    }

    private async Task LoadPets()
    {
        using var db = DbFactory.CreateDbContext();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private async Task LoadAppointments()
    {
        using var db = DbFactory.CreateDbContext();
        var dayStart = selectedDate.Date;
        var dayEnd = dayStart.AddDays(1);
        appointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= dayStart && a.StartTime < dayEnd)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        CalculateAvailableSlots();
    }

    private void CalculateAvailableSlots()
    {
        availableSlots.Clear();
        var clinicStart = selectedDate.Date.AddHours(8);
        var clinicEnd = selectedDate.Date.AddHours(18);

        for (var slot = clinicStart; slot < clinicEnd; slot = slot.AddMinutes(30))
        {
            var slotEnd = slot.AddMinutes(30);
            var isOccupied = appointments
                .Where(a => a.Status != AppointmentStatus.Cancelled)
                .Any(a => a.StartTime < slotEnd && a.EndTime > slot);
            if (!isOccupied)
            {
                availableSlots.Add(slot);
            }
        }
    }

    private void ShowNewAppointment()
    {
        var nextSlot = availableSlots.FirstOrDefault();
        if (nextSlot == default) nextSlot = selectedDate.Date.AddHours(9);
        editingAppointment = new Appointment
        {
            StartTime = nextSlot,
            EndTime = nextSlot.AddMinutes(30)
        };
        showForm = true;
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = new Appointment
        {
            Id = appt.Id,
            PetId = appt.PetId,
            StartTime = appt.StartTime,
            EndTime = appt.EndTime,
            Reason = appt.Reason,
            Veterinarian = appt.Veterinarian,
            Status = appt.Status,
            Notes = appt.Notes
        };
        showForm = true;
    }

    private async Task Cancel(Appointment appt)
    {
        using var db = DbFactory.CreateDbContext();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
            statusMessage = "Appointment cancelled.";
            await LoadAppointments();
        }
    }

    private async Task SaveAppointment()
    {
        using var db = DbFactory.CreateDbContext();
        if (editingAppointment!.Id == 0)
        {
            db.Appointments.Add(editingAppointment);
        }
        else
        {
            db.Appointments.Update(editingAppointment);
        }
        await db.SaveChangesAsync();
        statusMessage = "Appointment saved.";
        showForm = false;
        selectedDate = editingAppointment.StartTime.Date;
        await LoadAppointments();
    }

    private void PreviousDay() { selectedDate = selectedDate.AddDays(-1); _ = LoadAppointments(); }
    private void NextDay() { selectedDate = selectedDate.AddDays(1); _ = LoadAppointments(); }
    private void Today() { selectedDate = DateTime.Today; _ = LoadAppointments(); }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Cancelled => "table-secondary text-decoration-line-through",
        AppointmentStatus.Completed => "table-success",
        AppointmentStatus.InProgress => "table-info",
        _ => ""
    };

    private string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Confirmed => "bg-info",
        AppointmentStatus.InProgress => "bg-warning text-dark",
        AppointmentStatus.Completed => "bg-success",
