                    <td>@inv.Owner.FullName</td>
                    <td>@(inv.Pet?.Name ?? "-")</td>
                    <td>@inv.IssuedDate.ToShortDateString()</td>
                    <td>@inv.DueDate.ToShortDateString()</td>
                    <td>$@inv.TotalAmount.ToString("F2")</td>
                    <td>$@inv.AmountPaid.ToString("F2")</td>
                    <td><span class="badge @GetInvoiceBadge(inv.Status)">@inv.Status</span></td>
                    <td>
                        <a href="/billing/@inv.Id" class="btn btn-sm btn-info">Details</a>
                    </td>
                </tr>
            }
        </tbody>
    </table>
