@code {
    private List<Invoice> invoices = new();
    private List<Invoice> filteredInvoices = new();
    private List<Owner> owners = new();
    private List<Pet> pets = new();
    private string searchTerm = string.Empty;
    private string? statusMessage;
    private bool showForm;
    private Invoice? editingInvoice;
    private List<InvoiceLineItem> lineItems = new();
    private string selectedPetId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        using var db = DbFactory.CreateDbContext();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Pet)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        filteredInvoices = invoices;
    }

    private void FilterInvoices()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredInvoices = invoices;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredInvoices = invoices.Where(i =>
                i.InvoiceNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                i.Owner.FullName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                i.Description.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void ShowNewInvoice()
    {
        editingInvoice = new Invoice
        {
            DueDate = DateTime.Today.AddDays(30),
            Status = InvoiceStatus.Draft
        };
        lineItems = new List<InvoiceLineItem> { new() { Quantity = 1 } };
        selectedPetId = string.Empty;
        showForm = true;
    }

    private void AddLineItem()
    {
        lineItems.Add(new InvoiceLineItem { Quantity = 1 });
    }

    private async Task SaveInvoice()
    {
        using var db = DbFactory.CreateDbContext();
        editingInvoice!.TotalAmount = lineItems.Sum(l => l.Quantity * l.UnitPrice);
        editingInvoice.PetId = int.TryParse(selectedPetId, out var pid) ? pid : null;
        editingInvoice.IssuedDate = DateTime.UtcNow;

        if (editingInvoice.Id == 0)
        {
            editingInvoice.InvoiceNumber = $"INV-{DateTime.Now:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
            editingInvoice.LineItems = lineItems;
            db.Invoices.Add(editingInvoice);
        }
        else
        {
            db.Invoices.Update(editingInvoice);
        }
        await db.SaveChangesAsync();
        statusMessage = $"Invoice {editingInvoice.InvoiceNumber} saved.";
        showForm = false;
        await LoadData();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

