@page "/billing/{InvoiceId:int}"
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Invoice Details - VetClinic</PageTitle>

@if (invoice == null)
{
    <p>Loading...</p>
}
else
{
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h1>Invoice @invoice.InvoiceNumber</h1>
        <a href="/billing" class="btn btn-outline-secondary">← Back to Invoices</a>
    </div>

    <div class="row mb-4">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Invoice Information</div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Owner</dt>
                        <dd class="col-sm-8">@invoice.Owner.FullName</dd>
                        <dt class="col-sm-4">Pet</dt>
                        <dd class="col-sm-8">@(invoice.Pet?.Name ?? "N/A")</dd>
                        <dt class="col-sm-4">Issued</dt>
                        <dd class="col-sm-8">@invoice.IssuedDate.ToShortDateString()</dd>
                        <dt class="col-sm-4">Due</dt>
                        <dd class="col-sm-8">@invoice.DueDate.ToShortDateString()</dd>
                        <dt class="col-sm-4">Status</dt>
                        <dd class="col-sm-8"><span class="badge @GetInvoiceBadge(invoice.Status)">@invoice.Status</span></dd>
                        <dt class="col-sm-4">Description</dt>
                        <dd class="col-sm-8">@invoice.Description</dd>
                    </dl>
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header">Summary</div>
                <div class="card-body">
                    <dl class="row mb-0">
                        <dt class="col-sm-6">Total Amount</dt>
                        <dd class="col-sm-6 text-end"><strong>$@invoice.TotalAmount.ToString("F2")</strong></dd>
                        <dt class="col-sm-6">Amount Paid</dt>
                        <dd class="col-sm-6 text-end text-success">$@invoice.AmountPaid.ToString("F2")</dd>
                        <dt class="col-sm-6">Balance Due</dt>
                        <dd class="col-sm-6 text-end text-danger"><strong>$@invoice.BalanceDue.ToString("F2")</strong></dd>
                    </dl>
                </div>
            </div>
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table table-sm mb-4">
        <thead>
            <tr>
                <th>Description</th>
                <th>Qty</th>
                <th>Unit Price</th>
                <th>Total</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in invoice.LineItems)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>$@item.UnitPrice.ToString("F2")</td>
                    <td>$@item.Total.ToString("F2")</td>
                </tr>
            }
        </tbody>
    </table>

    <h4>Payment History</h4>
    <button class="btn btn-success mb-3" @onclick="ShowPaymentForm">+ Record Payment</button>

    @if (showPayForm)
    {
        <div class="card mb-3">
            <div class="card-header">Record Payment</div>
            <div class="card-body">
                <EditForm Model="newPayment" OnValidSubmit="SavePayment" FormName="payForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Amount</label>
                            <InputNumber class="form-control" @bind-Value="newPayment!.Amount" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Method</label>
                            <InputSelect class="form-select" @bind-Value="newPayment!.Method">
                                @foreach (var m in Enum.GetValues<PaymentMethod>())
                                {
                                    <option value="@m">@m</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Reference</label>
                            <InputText class="form-control" @bind-Value="newPayment!.Reference" />
                        </div>
                        <div class="col-md-3 mb-2">
                            <label class="form-label">Status</label>
                            <InputSelect class="form-select" @bind-Value="newPayment!.Status">
                                @foreach (var s in Enum.GetValues<PaymentStatus>())
                                {
                                    <option value="@s">@s</option>
                                }
                            </InputSelect>
                        </div>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newPayment!.Notes" />
                    </div>
                    <button type="submit" class="btn btn-success">Save Payment</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showPayForm = false">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    @if (statusMessage != null)
    {
        <div class="alert alert-success alert-dismissible">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    @if (invoice.Payments.Any())
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Amount</th>
                    <th>Method</th>
                    <th>Reference</th>
                    <th>Status</th>
                    <th>Notes</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pay in invoice.Payments.OrderByDescending(p => p.PaymentDate))
                {
                    <tr>
                        <td>@pay.PaymentDate.ToShortDateString()</td>
                        <td>$@pay.Amount.ToString("F2")</td>
                        <td>@pay.Method</td>
                        <td>@pay.Reference</td>
                        <td><span class="badge @GetPayBadge(pay.Status)">@pay.Status</span></td>
                        <td>@pay.Notes</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }
}

@code {
    [Parameter] public int InvoiceId { get; set; }

    private Invoice? invoice;
    private bool showPayForm;
    private Payment? newPayment;
    private string? statusMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        using var db = DbFactory.CreateDbContext();
        invoice = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Pet)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == InvoiceId);
    }

    private void ShowPaymentForm()
    {
        newPayment = new Payment
        {
            InvoiceId = InvoiceId,
            Amount = invoice!.BalanceDue,
            Method = PaymentMethod.Cash,
            Status = PaymentStatus.Completed
        };
        showPayForm = true;
    }

    private async Task SavePayment()
    {
        using var db = DbFactory.CreateDbContext();
        db.Payments.Add(newPayment!);
        await db.SaveChangesAsync();

        // Update invoice status if fully paid
        var inv = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == InvoiceId);
        var totalPaid = inv.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        if (totalPaid >= inv.TotalAmount)
        {
            inv.Status = InvoiceStatus.Paid;
            await db.SaveChangesAsync();
        }

        statusMessage = "Payment recorded.";
        showPayForm = false;
        await LoadInvoice();
    }

    private string GetInvoiceBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        InvoiceStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };

    private string GetPayBadge(PaymentStatus status) => status switch
    {
        PaymentStatus.Completed => "bg-success",
        PaymentStatus.Pending => "bg-warning text-dark",
        PaymentStatus.Failed => "bg-danger",
        PaymentStatus.Refunded => "bg-info",
        _ => "bg-secondary"
    };
}

