        todayAppointments = await db.Appointments
            .Where(a => a.StartTime >= today && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled)
            .CountAsync();

        pendingInvoices = await db.Invoices
            .Where(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue)
            .CountAsync();

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.Now && a.StartTime < tomorrow && a.Status != AppointmentStatus.Cancelled)
